function fromFV(v) {
  if (v == null) return null;
  if ('stringValue' in v) return v.stringValue;
  if ('integerValue' in v) return parseInt(v.integerValue);
  if ('doubleValue' in v) return parseFloat(v.doubleValue);
  if ('booleanValue' in v) return v.booleanValue;
  if ('nullValue' in v) return null;
  if ('timestampValue' in v) return v.timestampValue;
  if ('arrayValue' in v) return (v.arrayValue.values || []).map(fromFV);
  if ('mapValue' in v) return fromFF(v.mapValue.fields || {});
  return null;
}

function fromFF(fields) {
  const o = {};
  for (const k in fields) o[k] = fromFV(fields[k]);
  return o;
}

function parseDoc(doc) {
  const id = doc.name.split('/').pop();
  return { id, ...fromFF(doc.fields || {}) };
}

function parseTime(str) {
  if (!str) return null;
  str = str.trim();
  const ampm = str.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);
  if (ampm) {
    let h = parseInt(ampm[1]);
    const m = parseInt(ampm[2]);
    const period = ampm[3].toUpperCase();
    if (period === 'AM' && h === 12) h = 0;
    if (period === 'PM' && h !== 12) h += 12;
    return { h, m };
  }
  const plain = str.match(/^(\d{1,2}):(\d{2})$/);
  if (plain) return { h: parseInt(plain[1]), m: parseInt(plain[2]) };
  return null;
}

function getCairoTimeNow() {
  const now = new Date();
  const fmt = new Intl.DateTimeFormat('en-GB', {
    timeZone: 'Africa/Cairo',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  });
  const parts = fmt.formatToParts(now);
  const h = parseInt(parts.find(p => p.type === 'hour').value);
  const m = parseInt(parts.find(p => p.type === 'minute').value);
  return { h, m, totalMinutes: h * 60 + m };
}

const allItems = $input.all();
let members = {};
let tasks = [];

for (const item of allItems) {
  const docs = item.json.documents || [];
  if (!docs.length) continue;
  const path = docs[0].name || '';
  if (path.includes('/members/')) {
    for (const doc of docs) {
      const m = parseDoc(doc);
      members[m.id] = m;
    }
  }
  if (path.includes('/tasks/')) {
    tasks = docs.map(parseDoc);
  }
}

const cairoNow = getCairoTimeNow();
const reminderMinutes = 30;
const dedupeWindowMinutes = 1440;
const nowMs = Date.now();

const results = [];

for (const t of tasks) {
  if (t.status !== 'inprogress') continue;

  const assignees = (Array.isArray(t.assignees) && t.assignees.length)
    ? t.assignees
    : (t.assignee ? [t.assignee] : []);

  for (const aid of assignees) {
    const member = members[aid];
    if (!member || !member.phone || !member.shiftEnd) continue;

    const endTime = parseTime(member.shiftEnd);
    if (!endTime) continue;

    const shiftEndTotalMinutes = endTime.h * 60 + endTime.m;
    const minsToEnd = shiftEndTotalMinutes - cairoNow.totalMinutes;

    if (minsToEnd < 0 || minsToEnd > reminderMinutes) continue;

    const log = Array.isArray(t.activityLog) ? t.activityLog : [];
    const recentReminder = log.find(e => {
      if (!e || e.type !== 'reminder_sent') return false;
      if (e.memberId !== aid) return false;
      const ts = typeof e.timestamp === 'number' ? e.timestamp : 0;
      return (nowMs - ts) < (dedupeWindowMinutes * 60 * 1000);
    });
    if (recentReminder) continue;

    const deadline = (t.deadline && t.deadline !== '') ? new Date(t.deadline) : null;
    const deadlineStr = deadline && !isNaN(deadline)
      ? deadline.toLocaleString('en-GB', {
          day: '2-digit', month: 'short',
          hour: '2-digit', minute: '2-digit',
          hour12: false, timeZone: 'Africa/Cairo'
        })
      : 'غير محدد';

    const cleanPhone = member.phone.replace(/\D/g, '');
    const firstName = member.name.split(' ')[0];
    const progress = String(t.progress || 0);

    results.push({
      json: {
        taskId: t.id,
        memberId: aid,
        memberName: member.name,
        memberPhone: cleanPhone,
        firstName,
        taskName: t.name,
        deadlineStr,
        progress,
        currentActivityLog: t.activityLog || []
      }
    });
  }
}

return results;

