  if (typeof v === 'string') return { stringValue: v };
  if (typeof v === 'boolean') return { booleanValue: v };
  if (typeof v === 'number') {
    if (Number.isInteger(v)) return { integerValue: String(v) };
    return { doubleValue: v };
  }
  if (Array.isArray(v)) return { arrayValue: { values: v.map(toFV) } };
  if (typeof v === 'object') {
    const fields = {};
    for (const k in v) fields[k] = toFV(v[k]);
    return { mapValue: { fields } };
  }
  return { nullValue: null };
}

const decideItems = $('Decide Who To Notify').all();
const waItems = $input.all();

const entriesByTask = {};

for (let i = 0; i < decideItems.length; i++) {
  const decision = decideItems[i].json;
  const waRes = waItems[i]?.json;

  if (!waRes || !waRes.messages || !waRes.contacts) continue;

  const phone = waRes.contacts[0]?.wa_id;
  const msgId = waRes.messages[0]?.id;

  if (!phone || !msgId) continue;

  const newEntry = {
    source: 'system',
    type: 'reminder_sent',
    text: `Template reminder sent to ${decision.memberName} (+${phone})`,
    memberId: decision.memberId,
    memberName: decision.memberName,
    sentMessageId: msgId,
    timestamp: Date.now()
  };

  const tId = decision.taskId;
  if (!entriesByTask[tId]) entriesByTask[tId] = [];
  entriesByTask[tId].push(newEntry);
}

const output = [];
for (const taskId in entriesByTask) {
  output.push({
    json: {
      taskId,
      newEntries: entriesByTask[taskId]
    }
  });
}

return output;

