const buildItems = $('Build Log Entry').all();
const entryMap = {};
for (const item of buildItems) {
  const tId = item.json.taskId;
  const entries = item.json.newEntries || [];
  if (!entryMap[tId]) entryMap[tId] = [];
  entryMap[tId].push(...entries);
}

const tasks = $input.all();
const output = [];

for (const taskItem of tasks) {
  const taskDoc = taskItem.json;
  const taskId = taskDoc.name.split('/').pop();

  const newEntries = entryMap[taskId];
  if (!newEntries || newEntries.length === 0) continue;

  const currentLogFV = taskDoc.fields?.activityLog;
  const currentLog = currentLogFV
    ? (currentLogFV.arrayValue?.values || []).map(fromFV)
    : [];

  let updatedLog = [...currentLog];
  for (const newEntry of newEntries) {
    const exists = updatedLog.some(e =>
      e && e.sentMessageId === newEntry.sentMessageId && e.memberId === newEntry.memberId
    );
    if (!exists) updatedLog.push(newEntry);
  }

  output.push({
    json: {
      taskId,
      firestoreBody: { fields: { activityLog: toFV(updatedLog) } }
    }
  });
}

return output;
